import{_ as e,o as t,c as a,a as n}from"./app.076af709.js";const b=JSON.parse('{"title":"Dr_Oracle v. TheOrangeWizard, May 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/dr_oracle_v_theorangewizard_may_2018.md","lastUpdated":1666477380000}'),r={name:"government/court-cases-precedents/dr_oracle_v_theorangewizard_may_2018.md"},i=n('<h1 id="dr-oracle-v-theorangewizard-may-2018" tabindex="-1">Dr_Oracle v. TheOrangeWizard, May 2018 <a class="header-anchor" href="#dr-oracle-v-theorangewizard-may-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With bgbba, presiding, on 25th May 2018, Dr_Oracle sued TheOrangeWizard alleging the unwarranted removal of his citizenship. TheOrangeWizard was ordered to restore Dr_Oracle&#39;s citizenship.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>Dr_Oracle</strong>:</p><p>I&#39;d like to bring TheOrangeWizard to trial for unwarranted removal of my citizenship</p><p><strong>bgbba</strong>:</p><p>I will preside Dr_Oracle Please State your case</p><p><strong>Dr_Oracle</strong>:</p><p>I have been an active citizen for 7 months, and have contributed a considerable amount of wealth time and &#39;wisdom&#39; to Yoahtl. In the past week I have been very busy with assignments, but I have still logged in intermittently to check on things. Removing my citizenship has ulterior motives in suppressing my criticism of the present regime</p><p><strong>bgbba</strong>:</p><p>TheOrangeWizard State your case</p><p><strong>TheOrangeWizard</strong>:</p><p>My legal justification is simple: Citizenship is granted at the discretion of the Alcuahtl. As to this particular case, while Dr Oracle has been a tremendously valuable contributor to Yoahtl in the past, he is no longer doing so. Should that change I would be more than happy to grant citizenship once again. He still has the ability to express his criticisms of me in the general channel</p><p><strong>Aki</strong>:</p><p>I\u2019d like to add that oracle has intentionally neglected logging on as a protest of yoahtl\u2019s government and has not sold Obsidian, leading to /secretprojects/ to get Obsidian.</p><p><strong>Dr_Oracle</strong>:</p><p>Thanks for confirming the one party state totalitarianism, Aki</p><p><strong>bgbba</strong>:</p><p>Oracle, do you believe that you are entitled to citizenship on the basis of past contributions?</p><p><strong>Dr_Oracle</strong>:</p><p>There has never been an instance of citizenship being revoked due to an explained temporary lull in activity Not once</p><p><strong>bgbba</strong>:</p><p>TheOrangeWizard Do you dispute this?</p><p><strong>TheOrangeWizard</strong>:</p><p>I can&#39;t think of any particular instance so no</p><p><strong>Aki</strong>:</p><p>Yes there is</p><p><strong>bgbba</strong>:</p><p>Example?</p><p><strong>Aki</strong>:</p><p>Me I had to be readded to groups</p><p><strong>Modshot</strong>:</p><p>you left</p><p><strong>Aki</strong>:</p><p>When I joined back after a few months of absence</p><p><strong>bgbba</strong>:</p><p>That didn\u2019t mean you were removed from citizenship ship</p><p><strong>Dr_Oracle</strong>:</p><p>Was your absence explained and temporary</p><p><strong>bgbba</strong>:</p><p>No</p><p><strong>Aki</strong>:</p><p>It was explained though</p><p><strong>bgbba</strong>:</p><p>It was explained</p><p><strong>Aki</strong>:</p><p>And clearly temporary</p><p><strong>Dr_Oracle</strong>:</p><p>Months isn&#39;t temporary</p><p><strong>bgbba</strong>:</p><p>But not temporary</p><p><strong>Aki</strong>:</p><p>I\u2019m here now</p><p><strong>bgbba</strong>:</p><p>Bro you left the discord and said you didn\u2019t want to be part of Yoahtl anymore</p><p><strong>Aki</strong>:</p><p>I said I didn\u2019t want to be doxxed Big difference</p><p><strong>Modshot</strong>:</p><p>Aki, bg held off you being taken out for the longest time but I held the order to revoke your citizenship</p><p><strong>Aki</strong>:</p><p>My heart is touched But I am a previous example</p><p><strong>bgbba</strong>:</p><p>Okay, does anybody else have anything to say?</p><p><strong>TheOrangeWizard</strong>:</p><p>I have no further comments</p><p><strong>Dr_Oracle</strong>:</p><p>Nothing further your honour</p><p><strong>bgbba</strong>:</p><p>Okay, so here&#39;s the dealio:</p><p>The Charter of Yoahtl explicitly states that citizenship is granted at the discretion of the Alcuahtl, but not held at the discretion of the Alcuahtl. What this means, and what has been practiced by all previous alcuahtls dealing with this situation, is clear. The precedent is clear: Citizenship is revoked on grounds of unexplained inactivity or inactivity with insufficient explanation. Oracle has both clearly explained why he is inactive (and remained active in discord), and also not been inactive for long enough or in total enough time to justify the revokation of citizenship.</p><p>Furthermore, while creating new citizenships falls to the Alcuahtl as he is in charge of foreign affairs, I hold that the council has an obligation under the charter to have a say in what occurs to citizens once they are granted citizenship, including potential revokation of citizenship. The Charter makes it clear that the Council of Yoahtl is in charge of internal affairs, and that these internal affairs are those which affect the citizens or occur within the territory of Yoahtl.</p><p>BustaNuht has remained councillor despite being far more inactive than Oracle. This is an unfair double standard that amounts to a violation of equal treatment under Article 1 Section 7.</p><p>I find that Dr_Oracle is entitled to his citizenship until his absence is no longer justified by his explanation for being absent. In addition, I would like to set the precedent that the Alcuahtl must prove that the government has a compelling interest in removing the citizenship, and that the justification for being absent is not sufficient.</p>',74),o=[i];function s(p,h,c,l,d,g){return t(),a("div",null,o)}const f=e(r,[["render",s]]);export{b as __pageData,f as default};
